type Query {
  viewer: Viewer!
  conversation(id: ID!): Conversation
  conversations(first: Int!, after: String, filter: ConversationFilter): ConversationConnection!
  message(id: ID!): Message
  run(id: ID!): Run
  models: [ModelInfo!]!
}

type Mutation {
  createConversation(input: CreateConversationInput!): CreateConversationPayload!
  sendMessage(input: SendMessageInput!): SendMessagePayload!
  createRun(input: CreateRunInput!): CreateRunPayload!
  cancelRun(input: CancelRunInput!): CancelRunPayload!
  submitToolResult(input: SubmitToolResultInput!): SubmitToolResultPayload!
  archiveConversation(input: ArchiveConversationInput!): ArchiveConversationPayload!
}

type Subscription {
  runEvents(conversationId: ID!): RunEvent!
  messageDeltas(conversationId: ID!): MessageDeltaEvent!
}

input SendMessageInput {
  conversationId: ID!
  content: [MessageInputBlock!]!
  attachments: [AttachmentInput!]
  clientRequestId: String
  stream: Boolean = true
  responseMode: ResponseMode = ASSISTANT
}

type SendMessagePayload {
  conversation: Conversation!
  userMessage: Message!
  run: Run!
}

type TextDeltaEvent {
  runId: ID!
  messageId: ID!
  delta: String!
  index: Int!
}

input TextInputBlock {
  text: String!
}

input ImageInputBlock {
  fileId: ID!
}

input ToolResultInputBlock {
  toolUseId: ID!
  content: JSON!
}

input MessageInputBlock {
  text: TextInputBlock
  image: ImageInputBlock
  toolResult: ToolResultInputBlock
}

type RunError {
  code: RunErrorCode!
  message: String!
  retryable: Boolean!
  providerRequestId: String
}

interface Node {
  id: ID!
}

scalar DateTime
scalar JSON

enum MessageRole {
  USER
  ASSISTANT
  SYSTEM
  TOOL
}

enum RunStatus {
  QUEUED
  RUNNING
  WAITING_FOR_TOOL
  COMPLETED
  FAILED
  CANCELED
}

type Conversation implements Node {
  id: ID!
  title: String
  createdAt: DateTime!
  updatedAt: DateTime!
  messages(first: Int!, after: String): MessageConnection!
  latestRun: Run
}

type Message implements Node {
  id: ID!
  role: MessageRole!
  content: [MessageContentBlock!]!
  createdAt: DateTime!
  runId: ID
}

type TextBlock {
  text: String!
}

type ToolUseBlock {
  toolUseId: ID!
  name: String!
  input: JSON!
}

type ToolResultBlock {
  toolUseId: ID!
  output: JSON!
}

union MessageContentBlock = TextBlock | ToolUseBlock | ToolResultBlock

type Run implements Node {
  id: ID!
  conversationId: ID!
  status: RunStatus!
  model: String!
  usage: UsageSummary!
  outputMessage: Message
}

type UsageSummary {
  inputTokens: Int!
  outputTokens: Int!
  latencyMs: Int
}

input SendMessageInput {
  conversationId: ID!
  text: String!
  stream: Boolean = true
}

type SendMessagePayload {
  conversation: Conversation!
  userMessage: Message!
  run: Run!
}

type Query {
  conversation(id: ID!): Conversation
}

type Mutation {
  sendMessage(input: SendMessageInput!): SendMessagePayload!
}

type Subscription {
  runEvents(conversationId: ID!): RunEvent!
}

union RunEvent = TextDeltaEvent | RunCompletedEvent | RunFailedEvent

type TextDeltaEvent {
  runId: ID!
  messageId: ID!
  delta: String!
}

type RunCompletedEvent {
  runId: ID!
  messageId: ID!
}

type RunFailedEvent {
  runId: ID!
  error: RunError!
}

type RunError {
  code: String!
  message: String!
  retryable: Boolean!
}
